#!/usr/bin/env bash
# ============================================================
# Student Attendance App — one-shot setup script
# Run this on YOUR machine. It will:
#   1. Extract the project (StudentAttendanceApp + attendance-backend)
#   2. npm install both folders
#   3. Tell you exactly how to start everything
# ============================================================
set -e

if ! command -v node >/dev/null 2>&1; then
  echo "ERROR: Node.js is not installed. Install Node 18+ first: https://nodejs.org"
  exit 1
fi

TARGET="${1:-student-attendance-project}"
echo ">> Extracting to ./$TARGET ..."
mkdir -p "$TARGET"
cd "$TARGET"

PAYLOAD_B64=''
echo "$PAYLOAD_B64" | base64 -d | tar xz

echo ""
echo ">> Installing backend dependencies..."
( cd attendance-backend && npm install --silent )

echo ""
echo ">> Installing frontend dependencies..."
( cd StudentAttendanceApp && npm install --silent )

cat <<EOF

============================================================
DONE. Project is ready at: $(pwd)
============================================================

To run everything, open THREE terminals:

  Terminal A  (Express API):
    cd $(pwd)/attendance-backend
    npm run dev
    # API: http://localhost:4000/health

  Terminal B  (Metro bundler):
    cd $(pwd)/StudentAttendanceApp
    npx react-native start

  Terminal C  (Android app — needs Android Studio + emulator running):
    cd $(pwd)/StudentAttendanceApp
    npx react-native run-android

LOGIN:  teacher@school.com  /  123456

The Express API is browser-viewable at http://localhost:4000
The React Native UI appears in the Android EMULATOR WINDOW (not a browser).
EOF
